r2f_osd_title = TextObject(bs_BA="Open Source Software Notice - fabričke postavke", cs_CZ="Open Source Software Notice - tovární nastavení", da_DK="Open Source Software Notice - fabriksindstillinger", de_DE="Open Source Software Notice - Werkseinstellungen", el_GR="Open Source Software Notice - Εργοστασιακές ρυθμίσεις", en_GB="Open Source Software Notice - Factory settings", es_ES="Open Source Software Notice - Ajustes predefinidos", fi_FI="Open Source Software Notice - tehdasasetukset", fr_FR="Open Source Software Notice - Réglages d'usine", hr_HR="Open Source Software Notice - tvorničke postavke", hu_HU="Open Source Software Notice - Gyári beállítások", it_IT="Open Source Software Notice - Configurazione iniziale", nl_NL="Open Source Software Notice - Fabrieksinstellingen", no_NO="Open Source Software Notice – fabrikkinnstillinger", pl_PL="Open Source Software Notice - Ustawienia fabryczne", pt_PT="Open Source Software Notice - Confgurações de fábrica", ro_RO="Open Source Software Notice - setări din fabrică", ru_RU="Open Source Software Notice - Заводские настройки", sk_SK="Open Source Software Notice - Nastavenia zo závodu", sl_SI="Open Source Software Notice – tovarniške nastavitve", sr_RS="Open Source Software Notice - fabrička podešavanja", sv_SE="Open Source Software Notice - Fabriksinställningar", tr_TR="Open Source Software Notice - Fabrika ayarları", uk_UA="Open Source Software Notice - Заводські настройки")
r2f_setup_system_r2f_confirmation_cancel_button = TextObject(bs_BA="Odustani", cs_CZ="Zrušit", da_DK="Afbryd", de_DE="Abbrechen", el_GR="Διακοπή", en_GB="Cancel", es_ES="Cancelar", fi_FI="Keskeytä", fr_FR="Annuler", hr_HR="Prekinuti", hu_HU="Mégse", it_IT="Annulla", nl_NL="Annuleren", no_NO="Avbryt", pl_PL="Anuluj", pt_PT="Cancelar", ro_RO="Întrerupere", ru_RU="Прервать", sk_SK="Prerušiť", sl_SI="Prekinitev", sr_RS="Prekid", sv_SE="Avbryt", tr_TR="İptal et", uk_UA="Скасувати")
r2f_setup_system_r2f_confirmation_infotext = TextObject(bs_BA="Fabričke postavke se ponovo uspostavljaju. To može potrajati neko vrijeme.\nVozilo se ne smije isključiti tokom ovog vremena!\nSistem se nanovo pokreće. Ovaj postupak se ne može prekinuti.\nŽelite li pokrenuti resetovanje?", cs_CZ="Obnoví se tovární nastavení. To může nějakou dobu trvat.\nVozidlo nesmíte během této doby vypnout!\nSystém restartuje. Tento postup se nesmí přerušit.\nChcete spustit obnovení?", da_DK="Fabriksindstillinger gendannes. Det kan tage noget tid.\nBilen må ikke slukkes i dette tidsrum!\nSystem genstartes. Denne proces kan ikke afbrydes.\nVil du starte nulstillingen?", de_DE="Die Werkseinstellungen werden wiederhergestellt. Dies kann einige Zeit dauern.\nDas Fahrzeug darf während dieser Zeit nicht ausgeschaltet werden!\nDas System wird neu gestartet. Dieser Vorgang kann nicht abgebrochen werden.\nMöchtest du das Zurücksetzen starten?", el_GR="Θα γίνει επαναφορά στις εργοστασιακές ρυθμίσεις. Αυτό μπορεί να διαρκέσει λίγο χρόνο.\nΤο όχημα δεν πρέπει να απενεργοποιηθεί κατά τη διάρκεια αυτού του χρονικού διαστήματος!\nΤο σύστημα θα επανεκκινηθεί. Αυτή η διαδικασία δεν μπορεί να ματαιωθεί.\nΘέλετε να ξεκινήσετε την επαναφορά;", en_GB="Restoring factory settings. This may take a while.\nThe vehicle must not be switched off in this time.\nThe system will be restarted. This process cannot be cancelled.\nWould you like to start the resetting process?", es_ES="Se restablecerán los ajustes predefinidos. Esto puede tardar un poco.\n¡El vehículo no se debe apagar durante ese tiempo!\nEl sistema se reiniciará. El proceso no se puede cancelar.\n¿Desea restablecer los ajustes ahora?", fi_FI="Tehdasasetukset palautetaan. Tämä saattaa kestää jonkin aikaa.\nAutoa ei saa sammuttaa sinä aikana!\nJärjestelmä käynnistyy uudelleen eikä menettelyä voi keskeyttää.\nHaluatko aloittaa tehdasasetusten palautuksen?", fr_FR="Rétablissement des réglages d'usine en cours. Cela peut prendre un certain temps.\nNe coupez en aucun cas l'alimentation du véhicule pendant cette période!\nLe système sera redémarré et cette procédure ne peut pas être annulée.\nSouhaitez-vous démarrer la réinitialisation?", hr_HR="Ponovno se uspostavljaju tvorničke postavke. To može potrajati izvjesno vrijeme.\nVozilo se tijekom tog vremena ne smije isključiti!\nSustav se pokreće iznova. Taj se postupak ne može prekinuti.\nŽelite li pokrenuti poništavanje?", hu_HU="A gyári beállítások visszaállításra kerülnek. Ez bizonyos időt vehet igénybe.\nEzen idő alatt nem szabad leállítani a járművet!\nA rendszer újraindul. Ezt a műveletet nem lehet megszakítani.\nEl szeretnéd indítani a visszaállítást?", it_IT="Verrà ripristinata la configurazione iniziale. L'operazione può richiedere un po' di tempo.\nDurante questo tempo la vettura non deve essere spenta!\nIl sistema verrà riavviato. Non è possibile interrompere questa operazione.\nAvviare l'azzeramento per ripristinare la configurazione iniziale?", nl_NL="De fabrieksinstellingen worden hersteld. Dit kan enige tijd duren.\nHet voertuig mag in deze tijd niet worden uitgeschakeld!\nHet systeem wordt opnieuw gestart. Dit proces kan niet worden afgebroken.\nWil je nu starten met het herstellen?", no_NO="Gjenoppretter fabrikkinnstillingene. Dette kan ta litt tid.\nDu kan ikke slå av bilen i dette tidsrommet!\nSystemet startes på nytt. Du kan ikke avbryte denne prosessen.\nVil du starte gjenoppretting?", pl_PL="Trwa przywracanie ustawień fabrycznych. Może to trochę potrwać.\nPrzez ten czas nie wolno wyłączać pojazdu!\nSystem zostanie uruchomiony ponownie. Tej operacji nie można przerywać.\nCzy chcesz rozpocząć resetowanie?", pt_PT="As configurações de fábrica serão repostas. Isto pode demorar algum tempo.\nDurante este período o veículo não pode ser desligado!\nO sistema será reiniciado. Este procedimento não pode ser interrompido.\nQueres mesmo fazer a reposição?", ro_RO="Se restabilesc setările din fabrică. Acest lucru poate dura.\nNu este permisă oprirea autovehiculului în acest timp!\nSistemul va reporni. Acest proces nu poate fi întrerupt.\nDoriţi să iniţiaţi resetarea?", ru_RU="Восстанавливаются заводские настройки. Это может занять некоторое время.\nВыключать автомобиль в течение этого времени запрещено!\nСистема перезапускается. Этот процесс не может быть отменен.\nВы хотите начать сброс настроек?", sk_SK="Obnovia sa výrobné nastavenia. To môže trvať krátky čas.\nPočas tejto doby sa vozidlo nesmie vypnúť!\nSystém sa reštartuje. Tento proces nie je možné zrušiť.\nChcete spustiť reset?", sl_SI="Vzpostavljanje tovarniških nastavitev. To lahko traja nekaj časa.\nVozila v tem času ni dovoljeno izključiti!\nSistem se bo znova zagnal. Tega postopka ni mogoče prekiniti.\nAli želite zagnati resetiranje?", sr_RS="Fabrička podešavanja se ponovo uspostavljaju. To može da potraje određeno vreme.\nVozilo ne sme da se isključi tokom ovog vremena!\nSistem se ponovo pokreće. Ovaj postupak ne može da se prekine.\nDa li želite pokrenuti resetovanje?", sv_SE="Fabriksinställningarna återställs. Detta kan ta en liten stund.\nFordonet får inte stängas av under tiden. Systemet startas om. Processen kan inte avbrytas.\nVill du starta återställningen?", tr_TR="Fabrika ayarları yeniden yükleniyor. Bu biraz zaman alabilir.\nBu süre içinde araç kapatılmamalıdır!\nSistem yeniden başlatılacak. Bu işlem iptal edilemez.\nSıfırlamayı başlatmak istiyor musun?", uk_UA="Відновлюються заводські налаштування. Це може зайняти деякий час.\nВимикати автомобіль протягом цього часу заборонено!\nСистема перезапускається. Цей процес не може бути скасований.\nВи хочете почати скидання налаштувань?")
r2f_setup_system_r2f_confirmation_reset_button = TextObject(bs_BA="Resetuj", cs_CZ="Vynulovat", da_DK="Nulstil", de_DE="Zurück­setzen", el_GR="Επαναφορά", en_GB="Reset", es_ES="Restablecer", fi_FI="Palauta tehdasasetukset", fr_FR="Réinitialiser", hr_HR="Poništiti", hu_HU="Visszaállítás", it_IT="Azzera", nl_NL="Herstellen", no_NO="Tilbakestill", pl_PL="Resetuj", pt_PT="Reset", ro_RO="Resetare", ru_RU="Сбросить", sk_SK="Pôvodné nastavenia", sl_SI="Resetiranje", sr_RS="Resetovanje", sv_SE="Återställ", tr_TR="Sıfırla", uk_UA="Скинути")
r2f_setup_system_r2f_disclaimer_continue_button = TextObject(bs_BA="Dalje", cs_CZ="Dále", da_DK="Fortsæt", de_DE="Weiter", el_GR="Συνέχεια", en_GB="Continue", es_ES="Siguiente", fi_FI="Eteenpäin", fr_FR="Suite", hr_HR="Dalje", hu_HU="Tovább", it_IT="Continua", nl_NL="Verder", no_NO="Fortsett", pl_PL="Dalej", pt_PT="Continuar", ro_RO="Continuare", ru_RU="Далее", sk_SK="Ďalej", sl_SI="Naprej", sr_RS="Dalje", sv_SE="Fortsätt", tr_TR="Devam", uk_UA="Далі")
r2f_setup_system_r2f_disclaimer_infotext = TextObject(bs_BA="Pomoću ove funkcije se mobilni podaci privremeno aktiviraju,\na svi podaci i sistemske postavke vozila se vraćaju na fabričke\npostavke, npr.:\n- Korisnička prava, lični korisnici i nalozi.\n- Podaci aplikacije i sistemski podaci, lične postavke, kao i preuzete aplikacije.\n- Svi memorisani digitalni ključevi. Oni se više ne mogu koristiti.\n\nZa uspješno provođenje je neophodna stabilna podatkovna veza.", cs_CZ="Tato funkce dočasně aktivuje mobilní data a resetuje všechna data vozidla a nastavení\nsystému do továrního nastavení, například:\n- Uživatelská práva, osobní uživatelé a účty.\n- Data aplikací a systému, osobní nastavení a stažené aplikace.\n- Všechny uložené digitální klíče. Tyto již nelze použít.\n\nPro úspěšné provedení je vyžadováno stabilní datové připojení.", da_DK="Med denne funktion aktiveres mobildata midlertidigt, og alle bilens data og\nsystemindstillinger nulstilles til fabriksindstillingerne, fx:\n- Brugerrettigheder, personlige brugere og konti.\n- App- og systemdata, personlige indstillinger samt downloadede apps.\n- Alle gemte digitale nøgler. Disse kan ikke længere anvendes.\n\nFor en korrekt udførelse er en stabil dataforbindelse nødvendig.", de_DE="Mit dieser Funktion werden die mobilen Daten temporär aktiviert und alle Daten und\nSystemeinstellungen des Fahrzeugs auf die Werkseinstellungen zurückgesetzt, z. B.:\n- Nutzerrechte, persönliche Nutzer und Konten.\n- App- und Systemdaten, persönliche Einstellungen sowie heruntergeladene Apps.\n- Alle gespeicherten digitalen Schlüssel. Diese können nicht mehr verwendet werden.\n\nFür eine erfolgreiche Ausführung ist eine stabile Datenverbindung erforderlich.", el_GR="Με αυτήν τη λειτουργία ενεργοποιούνται προσωρινά τα δεδομένα κινητής τηλεφωνίας και\nγίνεται επαναφορά όλων των δεδομένων και των ρυθμίσεων συστήματος του οχήματος στις\nεργοστασιακές ρυθμίσεις, π.χ.:\n- Δικαιώματα χρήστη, στοιχεία πρόσβασης προσωπικών λογαριασμών χρήστη και λογαριασμοί\n- Δεδομένα εφαρμογών και συστήματος, προσωπικές ρυθμίσεις, καθώς και ληφθείσες\n(downloaded) εφαρμογές.\n- Όλα τα αποθηκευμένα ψηφιακά κλειδιά. Αυτά δεν μπορούν πλέον να χρησιμοποιηθούν.\n\nΓια την επιτυχή εκτέλεση απαιτείται σταθερή σύνδεση δεδομένων.", en_GB="This function temporarily activates mobile data and restores all data and system settings for\nthe vehicle to the factory settings. This includes the following:\n- User rights, personal users and accounts.\n- App and system data, personal settings and downloaded apps.\n- All stored digital keys. These can then no longer be used.\n\nA stable data connection is required for this.", es_ES="Con esta función se activan temporalmente los datos móviles y se restablecen todos los\ndatos y ajustes de sistema del vehículo.\nEsto afecta, por ejemplo, a:\n- Derechos de usuario, usuarios y cuentas personales.\n- Datos de aplicaciones y sistema, ajustes personales y aplicaciones descargadas.\n- Todas las llaves digitales memorizadas. Ya no se podrán utilizar.\n\nSe necesita una conexión de datos estable.", fi_FI="Tällä toiminnolla mobiilidata aktivoidaan tilapäisesti ja kaikki auton tiedot\nja järjestelmäasetukset palautetaan tehdasasetuksiin, esim. seuraavat:\n- käyttöoikeudet, henkilökohtaiset käyttäjätunnukset ja tilit\n- sovellus- ja järjestelmätiedot, henkilökohtaiset asetukset ja ladatut sovellukset\n- kaikki tallennetut digitaaliset avaimet; niitä ei voi enää käyttää.\n\nToiminnon onnistuminen edellyttää vakaata datayhteyttä.", fr_FR="Cette fonction permet d'activer temporairement les données mobiles et de rétablir les\nréglages d'usine de toutes les données et de tous les réglages système du véhicule. Par ex.:\n- les droits d'utilisateur, les profils utilisateur personnalisés et les comptes.\n- les données des applis et des systèmes, les réglages personnels et les applis téléchargées.\n- toutes les clés numériques mémorisées. Ces clés ne peuvent alors plus être utilisées.\n\nUne connexion de données stable est nécessaire pour que la fonction puisse être exécutée.", hr_HR="Ovom se funkcijom privremeno aktiviraju mobilni podaci i svi se podaci i sistemske postavke\nvozila poništavaju na tvorničke postavke, npr.\n- korisnička prava, korisnici i korisnički računi\n- podaci aplikacija i sistemski podaci, osobne postavke kao i preuzete aplikacije\n- svi pohranjeni digitalni ključevi. Oni se više ne mogu koristiti.\n\nZa uspješnu provedbu potrebna je stabilna veza za prijenos podataka.", hu_HU="Ez a funkció ideiglenesen aktiválja a mobil adatokat, és visszaállítja az összes járműadatot és\nrendszerbeállítást a gyári beállításokra, például:\n- Felhasználói jogok, személyes felhasználók és fiókok.\n- Alkalmazás- és rendszeradatok, személyes beállítások és letöltött alkalmazások.\n- Minden mentett digitális kulcs. Ezeket már nem lehet használni.\n\nA sikeres végrehajtáshoz stabil adatkapcsolat szükséges.", it_IT="Con questa funzione vengono attivati temporaneamente i dati mobili e viene ripristinata la\nconfigurazione iniziale di tutti i dati e tutte le impostazioni di sistema della vettura, ad es.:\n- Diritti utente, account e utenti personali.\n- Dati delle app e dati di sistema, impostazioni personali e app scaricate.\n- Tutte le chiavi digitali memorizzate. Queste non potranno più essere utilizzate.\n\nPer un'esecuzione corretta è necessario un collegamento dati stabile.", nl_NL="Met deze functie worden de mobiele data tijdelijk geactiveerd en alle gegevens en\nsysteeminstellingen van het voertuig teruggezet naar de fabrieksinstellingen, bijv.\n- gebruikersrechten, persoonlijke gebruikers en accounts;\n- app- en systeemgegevens, persoonlijke instellingen en gedownloade apps;\n- alle opgeslagen digitale sleutels. Deze kunnen niet meer worden gebruikt.\n\nVoor een succesvolle uitvoering is een stabiele dataverbinding vereist.", no_NO="Denne funksjonen aktiverer mobildata midlertidig og tilbakestiller alle data og\nsysteminnstillinger i bilen til fabrikkinnstillinger, f.eks.:\n- brukerrettigheter, personlige brukere og kontoer.\n- app- og systemdata, personlige innstillinger og nedlastede apper.\n- alle lagrede digitale nøkler. Deretter kan de ikke brukes lenger.\n\nDu må ha en stabil dataforbindelse for at det skal fungere.", pl_PL="Ta funkcja tymczasowo włącza dane mobilne oraz przywraca wszystkie dane i ustawienia\nsystemowe pojazdu do ustawień fabrycznych, np:\n- uprawnienia użytkowników, użytkowników osobistych i kont\n- dane aplikacji i systemów, ustawienia osobiste oraz pobrane aplikacje,\n- wszystkie zapisane klucze cyfrowe. Korzystanie z nich przestanie być możliwe.\n\nDo pomyślnego wykonania niezbędne jest stabilne połączenie transmisji danych.", pt_PT="Com esta função os dados móveis são temporariamente ativados e são repostas as\nconfigurações de fábrica dos ajustes do sistema do veículo, por ex.:\n- Direitos de utilizador, utilizador pessoal e contas.\n- Dados da App e do sistema, ajustes pessoais e também Apps descarregadas.\n- Todas as chaves digitais guardadas. Estas já não podem ser utilizadas.", ro_RO="Cu această funcţie sunt activate temporar datele mobile şi sunt resetate toate datele şi\nsetările de sistem ale autovehiculului dumneavoastră la setările din fabrică, de exemplu:\n- Drepturile utilizatorilor, utilizatorii personali şi conturile.\n- Datele aplicaţiilor şi de sistem, setările personale, precum şi aplicaţiile descărcate.\n- Toate cheile digitale memorate. Acestea nu vor mai putea fi utilizate.\n\nPentru executarea cu succes este necesară o conexiune de date stabilă.", ru_RU="Эта функция временно активирует мобильные данные и сбрасывает все данные и\nсистемные настройки автомобиля на заводские настройки, например:\n- права пользователей, личные данные пользователей и учетные записи.\n- данные приложений и системы, персональные настройки и загруженные приложения.\n- все сохраненные цифровые ключи. Затем их больше нельзя будет использовать.\n\nДля успешного выполнения требуется стабильный канал передачи данных.", sk_SK="Pomocou tejto funkcie sa dočasne aktivujú mobilné dáta a vynulujú sa všetky dáta vozidla a\nnastavenia systému na nastavenia z výroby, napr.:\n– Používateľské práva, osobný používatelia a účty.\n– Dáta aplikácií a systému, osobné nastavenia, ako aj stiahnuté aplikácie.\n– Všetky uložené digitálne kľúče. Tie už potom nie je možné použiť.\n\n Na úspešné vykonanie je potrebné stabilné dátové pripojenie.", sl_SI="S to funkcijo se začasno aktivirajo mobilni podatki. Vsi podatki in sistemske nastavitve vozila\nse resetirajo na tovarniške nastavitve, na primer:\n- uporabniške pravice, osebni uporabniki in računi,\n- podatki aplikacij in sistemov, osebne nastavitve in prenesene aplikacije,\n- vsi shranjeni digitalni ključi; teh ključev ni več mogoče uporabljati.\n\nZa uspešno izvedbo je potrebna stabilna podatkovna povezava.", sr_RS="Pomoću ove funkcije se svi mobilni podaci aktiviraju privremeno, a svi\npodaci i sistemska podešavanja vozila se vraćaju na fabrička podešavanja, npr.:\n- Korisnička prava, lični korisnici i nalozi.\n- Podaci o aplikacijama i sistemu, lična podešavanja, kao i preuzete aplikacije.\n- Svi sačuvani digitalni ključevi. Oni se nakon toga više ne mogu koristiti.\nZa uspešno izvođenje je neophodan stabilan prenos podataka.", sv_SE="Med den här funktionen aktiveras mobildata tillfälligt och alla data och systeminställningar\nför fordonet återställs till fabriksinställningarna, t.ex.:\n- Användarrättigheter, personliga användare och konton.\n- App- och systemdata, personliga inställningar och nedladdade appar.\n- Alla sparade digitala nycklar. Dessa kan sedan inte användas längre.\n\nFör att det ska fungera korrekt krävs en stabil internetanslutning.", tr_TR="Bu fonksiyon ile mobil veriler geçici olarak etkinleştirilir ve aracın tüm verileri ve sistem\nayarları fabrika ayarlarına sıfırlanır, örneğin:\n- Kullanıcı hakları, kişisel kullanıcılar ve hesaplar.\n- Uygulama ve sistem verileri, kişisel ayarlar ve indirilen uygulamalar.\n- Kaydedilen tüm dijital anahtarlar. Bunlar artık kullanılamaz.\n\nBaşarılı bir yürütme için istikrarlı bir veri bağlantısı gereklidir.", uk_UA="Ця функція тимчасово активує мобільні дані та скидає всі дані та системні налаштування\nавтомобіля на заводські настройки, наприклад:\n- права користувачів, особисті дані користувачів та облікові записи.\n- дані програм та системи, персональні налаштування та завантажені програми.\n- усі збережені цифрові ключі. Потім їх вже не можна буде використовувати.\n\nДля успішного виконання потрібне стабільне з'єднання для передачі даних.")
r2f_setup_system_r2f_not_possible_fleet_infotext = TextObject(bs_BA="Ovo vozilo je dio voznog parka. Operater voznog parka je ograničio resetovanje\nvozila. Detaljne informacije možete dobiti kod Vašeg operatera voznog parka.", cs_CZ="Toto vozidlo je součástí vozového parku. Provozovatel vozového parku omezil resetování\nvozidla. Další informace získáte u provozovatele vozového parku.", da_DK="Denne bil er en del af en flåde. Flådeejeren har begrænset nulstillingen af bilen.\nDu får yderligere informationer hos flådeejeren.", de_DE="Dieses Fahrzeug ist Teil einer Flotte. Der Flottenbetreiber hat das Zurücksetzen des Fahrzeugs\neingeschränkt. Nähere Informationen erhältst du beim Flottenbetreiber.", el_GR="Αυτό το όχημα είν.μέρος ενός στόλου. Ο φορέας διαχείρ.τ.στόλου έχει περιορ.τ.επαναφ.(reset)\nτου οχήματος. Θα βρείτε περισσότερες πληροφορίες στον φορέα διαχείρισης του στόλου.", en_GB="This vehicle is part of a fleet. The fleet operator has set restrictions on resetting the vehicle.\nMore detailed information is available from the fleet operator.", es_ES="Este vehículo forma parte de una flota. El operador de la flota ha restringido el\nrestablecimiento del vehículo. Para más información, consulte al operador de la flota.", fi_FI="Tämä auto kuuluu autokalustoon. Autokaluston ylläpitäjä on rajoittanut auton nollaamista.\nLisätietoja saat autokaluston ylläpitäjältä.", fr_FR="Ce véhicule fait partie d'une flotte. Le gestionnaire de flotte a limité la réinitialisation du\nvéhicule. Vous pouvez obtenir de plus amples informations auprès du gestionnaire de flotte.", hr_HR="Ovo je vozilo dio flote. Flotni operater ograničio je poništavanje postavki vozila. Podrobnije\ninformacije možete dobiti kod flotnog operatera.", hu_HU="Ez a jármű egy flotta része. A flottaüzemeltető korlátozta a jármű visszaállítását. További\ninformációért fordulj a flottaüzemeltetőhöz.", it_IT="Questa vettura fa parte di una flotta. Il gestore della flotta ha limitato l'azzeramento della\nvettura. Per maggiori informazioni consultare il gestore della flotta.", nl_NL="Dit voertuig maakt deel uit van een wagenpark. De wagenparkbeheerder heeft het opnieuw\ninstellen van het voertuig beperkt. Neem voor meer informatie contact op met de beheerder.", no_NO="Bilen inngår i en bilpark. Bilparkoperatøren har begrenset muligheten for tilbakestilling av\nbilen. Du får mer informasjon av bilparkoperatøren.", pl_PL="Ten pojazd jest częścią floty. Operator floty ograniczył możliwość resetowania pojazdu.\nAby uzyskać więcej informacji, skontaktuj się z operatorem floty.", pt_PT="Este veículo faz parte de uma frota. O Gestor da frota restringiu o reset do veículo. Podes\nobter informações mais detalhadas junto do Gestor de frota.", ro_RO="Acest autovehicul face parte dintr-o flotă. Operatorul de flotă a restricţionat resetarea\nautovehiculului. Informaţii suplimentare obţineţi de la operatorul de flotă.", ru_RU="Этот а/м входит в состав автопарка. Оператор автопарка ограничил сброс настроек\nа/м. Для получения дополнительной информации обратитесь к оператору автопарка.", sk_SK="Toto vozidlo je súčasťou flotily. Prevádzkovateľ flotily obmedzil resetovanie vozidla. Bližšie\ninformácie získate od prevádzkovateľa flotily.", sl_SI="To vozilo je del voznega parka. Upravitelj voznega parka je omejil resetiranje vozila.\nPodrobnejše informacije najdete pri upravitelju voznega parka.", sr_RS="Ovo vozilo je deo voznog parka. Operater voznog parka je ograničio resetovanje\nvozila. Detaljnije informacije možete dobiti kod vašeg operatera voznog parka.", sv_SE="Din bil ingår i en fordonspark. Fordonsparksägaren har begränsat återställning av bilen. Du\nkan få mer information av fordonsparksägaren.", tr_TR="Bu araç bir filonun parçasıdır. Filo işletmecisi aracın sıfırlanmasını kısıtlamıştır. Daha detaylı\nbilgiyi filo işletmecisinden alabilirsin.", uk_UA="Цей автомобіль є частиною автопарку. Оператор автопарку обмежив скидання автомобіля.\nДля отримання додаткової інформації, будь ласка, зверніться до оператора автопарку.")
