texttool_globals_toast___r2f_function_unavailable_clamp15_off = TextObject(bs_BA="Uključite vozilo kako biste mogli koristiti ovu funkciju.", cs_CZ="Zapněte prosím vozidlo, abyste mohli využívat tuto funkci.", da_DK="Start bilen for at kunne anvende denne funktion.", de_DE="Bitte schalte das Fahrzeug ein, um diese Funktion\nnutzen zu können.", el_GR="Ενεργοποιήστε το όχημα, για να μπορέσετε να χρησιμοποιήσετε\nαυτή τη λειτουργία.", en_GB="Please switch the vehicle on to use this function.", es_ES="Encienda el vehículo para poder utilizar esta función.", fi_FI="Kytke auto päälle käyttääksesi tätä toimintoa.", fr_FR="Veuillez établir l'alimentation du véhicule pour pouvoir\nutiliser cette fonction.", hr_HR="Uključite vozilo kako biste koristili ovu funkciju.", hu_HU="Ennek a funkciónak a használatához kapcsold be a járművet.", it_IT="Accendere la vettura per poter utilizzare questa funzione.", nl_NL="Schakel het voertuig in om deze functie te kunnen gebruiken.", no_NO="Du må slå på bilen for å bruke denne funksjonen.", pl_PL="Aby móc korzystać z tej funkcji, proszę włączyć pojazd.", pt_PT="Por favor, liga o veículo para poderes utilizar esta função.", ro_RO="Activaţi autovehiculul, pentru a putea utiliza această funcţie.", ru_RU="Чтобы воспользоваться этой функцией, включите автомобиль.", sk_SK="Prosím, zapnite vozidlo, aby ste mohli používať túto funkciu.", sl_SI="Za uporabo te funkcije vključite vozilo.", sr_RS="Uključite vozilo da biste mogli koristiti ovu funkciju.", sv_SE="Starta fordonet för att kunna använda denna funktion.", tr_TR="Bu fonksiyonu kullanabilmek için lütfen aracı aç.", uk_UA="Щоб скористатися цією функцією, увімкніть автомобіль.")
texttool_globals_toast___r2f_function_unavailable_during_software_update = TextObject(bs_BA="Ova funkcija nije raspoloživa tokom aktualizacije.", cs_CZ="Tato funkce je během updatu nedostupná.", da_DK="Denne funktion er ikke tilgængelig under en opdatering.", de_DE="Diese Funktion ist während eines Updates nicht verfügbar.", el_GR="Αυτή λειτουργία δεν είναι διαθέσιμη κατά τη διάρκεια μιας\nαναβάθμισης.", en_GB="This function is not available during an update.", es_ES="Esta función no está disponible durante una actualización.", fi_FI="Tämä toiminto ei ole käytettävissä päivityksen aikana.", fr_FR="Cette fonction n'est pas disponible durant une mise à jour.", hr_HR="Ova funkcija tijekom updatea nije raspoloživa.", hu_HU="Ez a funkció frissítés közben nem áll rendelkezésre.", it_IT="Questa funzione non è disponibile durante un update.", nl_NL="Deze functie is tijdens een update niet beschikbaar.", no_NO="Denne funksjonen er ikke tilgjengelig under en oppdatering.", pl_PL="Ta funkcja jest niedostępna w trakcie aktualizacji.", pt_PT="Esta função não está disponível durante uma atualização.", ro_RO="Această funcţie nu este disponibilă în timpul unei actualizări.", ru_RU="Эта функция недоступна во время обновления.", sk_SK="Táto funkcia počas aktualizácie nie je k dispozícii.", sl_SI="Ta funkcija med posodabljanjem ni na voljo.", sr_RS="Ova funkcija nije dostupna tokom ažuriranja.", sv_SE="Denna funktion är inte tillgänglig under en uppdatering.", tr_TR="Bu fonksiyon bir güncelleme sırasında mevcut değildir.", uk_UA="Ця функція недоступна під час оновлення.")
